import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{n as i,r as a,t as o}from"./chunks/macos-password-prompt.BkxO9RJk.js";const s=JSON.parse(`{"title":"在 macOS 上安装 Java","description":"在 macOS 上安装 Java 的逐步指南。","frontmatter":{"title":"在 macOS 上安装 Java","description":"在 macOS 上安装 Java 的逐步指南。","authors":["dexman545","ezfe"],"next":false,"files":[]},"headers":[],"relativePath":"zh_cn/players/installing-java/macos.md","filePath":"translated/zh_cn/players/installing-java/macos.md","lastUpdated":1771183440000}`);var c={name:`zh_cn/players/installing-java/macos.md`};function l(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">在 macOS 上安装 Java <a class="header-anchor" href="#h1" aria-label="Permalink to “在 macOS 上安装 Java”">​</a></h1><p>本指南将会指引你在 macOS 上安装 Java 21。</p><p>Minecraft 启动器自带 Java 安装，因此本节仅在你想要使用 Fabric 的 <code>.jar</code> 安装程序，或想要使用 Minecraft 服务器 <code>.jar</code> 时才相关。</p><h2 id="1-check-if-java-is-already-installed" tabindex="-1">1. 检查 Java 是否已经安装 <a class="header-anchor" href="#1-check-if-java-is-already-installed" aria-label="Permalink to “1. 检查 Java 是否已经安装”">​</a></h2><p>在终端（位于 <code>/Applications/Utilities/Terminal.app</code>）中输入以下命令，然后按 <kbd>Enter</kbd> 键：</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/usr/libexec/java_home</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -v</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 21</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)/bin/java --version</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>你应该会看到类似以下内容：</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>openjdk 21.0.9 2025-10-21 LTS</span></span>
<span class="line"><span>OpenJDK Runtime Environment Temurin-21.0.9+10 (build 21.0.9+10-LTS)</span></span>
<span class="line"><span>OpenJDK 64-Bit Server VM Temurin-21.0.9+10 (build 21.0.9+10-LTS, mixed mode, sharing)</span></span></code></pre></div><p>请注意版本号：在上例中，版本号为 <code>21.0.9</code>。</p><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>要使用 Minecraft 1.21.11，你至少需要安装 Java 21。</p><p>如果此命令显示的版本低于 21，则需要更新现有的 Java 安装，请继续阅读本页。</p></div><h2 id="2-downloading-and-installing-java" tabindex="-1">2. 下载并安装 Java 21 <a class="header-anchor" href="#2-downloading-and-installing-java" aria-label="Permalink to “2. 下载并安装 Java 21”">​</a></h2><p>我们推荐使用 <a href="https://adoptium.net/temurin/releases?version=21&amp;os=mac&amp;arch=any&amp;mode=filter" target="_blank" rel="noreferrer">Adoptium 构建的 OpenJDK 21</a>：</p><p><img src="/assets/players/installing-java/macos-download-java.png" alt="Temurin Java 下载页面" loading="lazy"></p><p>请务必选择“21 - LTS”版本，并选择 <code>.PKG</code> 安装程序格式。 你还应根据你系统的芯片选择正确的架构：</p><ul><li>如果你使用的是 Apple M 系列芯片，请选择 <code>aarch64</code>（默认）</li><li>如果你使用的是 Intel 芯片，请选择 <code>x64</code></li><li>请按照此说明<a href="https://support.apple.com/zh-cn/116943" target="_blank" rel="noreferrer">了解你的 Mac 中安装的是哪种芯片</a></li></ul><p>下载 <code>.pkg</code> 安装程序后，打开它并按照提示操作：</p><p><img src="/assets/players/installing-java/macos-installer.png" alt="Temurin Java 安装程序" loading="lazy"></p><p>你需要输入管理员密码才能完成安装：</p><p><img src="/assets/players/installing-java/macos-password-prompt.png" alt="macOS 密码提示" loading="lazy"></p><h3 id="using-homebrew" tabindex="-1">使用 Homebrew <a class="header-anchor" href="#using-homebrew" aria-label="Permalink to “使用 Homebrew”">​</a></h3><p>如果你已经安装了 <a href="https://brew.sh" target="_blank" rel="noreferrer">Homebrew</a>，则可以改用 <code>brew</code> 安装 Java 21：</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">brew</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --cask</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> temurin@21</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="3-verify-that-java-is-installed" tabindex="-1">3. 验证是否已安装 Java 21 <a class="header-anchor" href="#3-verify-that-java-is-installed" aria-label="Permalink to “3. 验证是否已安装 Java 21”">​</a></h2><p>安装完成后，你可以再次打开终端并输入 <code>$(/usr/libexec/java_home -v 21)/bin/java --version</code> 来验证 Java 21 是否已安装。</p><p>如果命令执行成功，你应该会看到类似这样的输出：</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>openjdk 21.0.9 2025-10-21 LTS</span></span>
<span class="line"><span>OpenJDK Runtime Environment Temurin-21.0.9+10 (build 21.0.9+10-LTS)</span></span>
<span class="line"><span>OpenJDK 64-Bit Server VM Temurin-21.0.9+10 (build 21.0.9+10-LTS, mixed mode, sharing)</span></span></code></pre></div><p>如有任何问题，欢迎在 <a href="https://discord.fabricmc.net/" target="_blank" rel="noreferrer">Fabric Discord</a> 的 <code>#player-support</code> 频道中提问。</p>`,27)]])}var u=r(c,[[`render`,l]]);export{s as __pageData,u as default};